// @vitest-environment node
/**
 * SPEC-048: Búsqueda global adaptada al modelo v3 (capa main,
 * src/main/db/search.ts) contra el store REAL inyectado (patrón
 * tests/unit/persistence): las empresas son globales y entran SIEMPRE (incluso
 * en un sistema sin discoveries — deroga la omisión defensiva del ancla
 * transicional de SPEC-043), y el índice nuevo de grupos de entrevistas
 * (matching NFD compartido, contexto discoveryName resuelto en main, límite 8,
 * discovery irresoluble → hit omitido).
 * Generated by QA Dev agent.
 */
import { mkdtempSync, writeFileSync } from 'fs'
import { tmpdir } from 'os'
import { join } from 'path'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import * as repository from '../../../src/main/db/repository'
import { searchGlobal } from '../../../src/main/db/search'
import { initStore } from '../../../src/main/db/store'

vi.mock('electron', () => ({
  app: {
    getPath: (): string => {
      throw new Error('app.getPath no debe usarse en tests: initStore recibe baseDir inyectado')
    }
  }
}))

let baseDir = ''

beforeEach(() => {
  baseDir = mkdtempSync(join(tmpdir(), 'maurya-search-v3-'))
  initStore(baseDir)
})

describe('searchGlobal (SPEC-048 v3)', () => {
  describe('global companies', () => {
    // SPEC-048 · AC-02 (main: deroga la omisión defensiva del ancla
    // transicional de SPEC-043 — sin NINGÚN discovery en el sistema, la
    // empresa coincidente aparece con el shape global { id, name })
    it('returns matching company hits in a system with zero discoveries', () => {
      const company = repository.createCompany({ name: 'Acmé Córp' })

      const results = searchGlobal('acme')

      expect(results.discoveries).toEqual([])
      expect(results.companies).toEqual([{ id: company.id, name: 'Acmé Córp' }])
    })
  })

  describe('interview groups index', () => {
    // SPEC-048 · AC-04 (main: coincidencia por nombre de grupo con la MISMA
    // normalización NFD del resto — acentos/mayúsculas en ambos sentidos — y
    // hit con el nombre del discovery como contexto resuelto)
    it('matches groups by normalized name in both directions carrying the discovery name as context', () => {
      const discovery = repository.createDiscovery({ name: 'Vertical Sanidad' })
      const group = repository.createInterviewGroup({
        discoveryId: discovery.id,
        name: 'Sesión Fundadores'
      })

      // Query sin acentos encuentra el nombre acentuado…
      expect(searchGlobal('sesion fundadores').groups).toEqual([
        {
          id: group.id,
          discoveryId: discovery.id,
          name: 'Sesión Fundadores',
          discoveryName: 'Vertical Sanidad'
        }
      ])
      // …y la query acentuada/mayúscula encuentra igualmente
      expect(searchGlobal('SESIÓN').groups).toHaveLength(1)
    })

    // SPEC-048 · AC-06 (main: máximo 8 hits de grupo, igual que el resto)
    it('caps the groups hit list at 8 results', () => {
      const discovery = repository.createDiscovery({ name: 'Vertical Sanidad' })
      for (let index = 1; index <= 10; index += 1) {
        repository.createInterviewGroup({
          discoveryId: discovery.id,
          name: `Grupo ${index}`
        })
      }

      const results = searchGlobal('grupo')
      expect(results.groups).toHaveLength(8)
      expect(results.groups[0].name).toBe('Grupo 1')
      expect(results.groups[7].name).toBe('Grupo 8')
    })

    // SPEC-048 · AC-08 (main: un grupo cuyo discovery no resuelve — dato
    // inconsistente escrito a mano — se omite defensivamente; la búsqueda
    // nunca rompe)
    it('omits group hits whose discovery does not resolve', () => {
      const now = '2026-07-16T09:00:00.000Z'
      writeFileSync(
        join(baseDir, 'db.json'),
        // Schema v3 escrito a mano: un grupo válido y otro huérfano (su
        // discovery no existe) que comparten la subcadena buscada
        JSON.stringify({
          schemaVersion: 3,
          discoveries: [
            {
              id: 'd-1',
              name: 'Vertical Sanidad',
              objectives: null,
              createdAt: now,
              updatedAt: now
            }
          ],
          companies: [],
          contacts: [],
          interviewTemplates: [],
          interviewGroups: [
            {
              id: 'g-ok',
              discoveryId: 'd-1',
              name: 'Grupo con discovery',
              objective: null,
              interviewTemplateId: null,
              noteTemplateId: null,
              createdAt: now,
              updatedAt: now
            },
            {
              id: 'g-broken',
              discoveryId: 'd-ghost',
              name: 'Grupo huérfano',
              objective: null,
              interviewTemplateId: null,
              noteTemplateId: null,
              createdAt: now,
              updatedAt: now
            }
          ],
          interviews: [],
          noteTemplates: [],
          notes: []
        })
      )
      initStore(baseDir)

      expect(searchGlobal('grupo').groups).toEqual([
        {
          id: 'g-ok',
          discoveryId: 'd-1',
          name: 'Grupo con discovery',
          discoveryName: 'Vertical Sanidad'
        }
      ])
    })
  })
})
